import{c as t,Q as n,j as s,m as a}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Customers, Tenants & Instances","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/customers-tenants-instances.md","filePath":"guide/concepts/customers-tenants-instances.md","lastUpdated":1778912818000}'),o={name:"guide/concepts/customers-tenants-instances.md"};function i(r,e,l,c,u,h){return n(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="customers-tenants-instances" tabindex="-1">Customers, Tenants &amp; Instances <a class="header-anchor" href="#customers-tenants-instances" aria-label="Permalink to &quot;Customers, Tenants &amp; Instances&quot;">​</a></h1><p>These three nouns appear everywhere in the Console. Getting them right makes the rest of the guide read cleanly.</p><h2 id="customer" tabindex="-1">Customer <a class="header-anchor" href="#customer" aria-label="Permalink to &quot;Customer&quot;">​</a></h2><p>A <strong>customer</strong> is a company you have a contract with. Customers are the unit of:</p><ul><li>Contracting and billing. A customer is on exactly one plan at a time, and one or more versions of that plan over time.</li><li>Identity. A customer has its own Zitadel organisation, its own password policy, its own MFA policy, and its own identity providers.</li><li>The customer portal. Every URL under <code>/customers/:customerId/...</code> is scoped to one customer.</li></ul><p>A customer can have many tenants, but a tenant always belongs to exactly one customer.</p><p>Customers have a lifecycle:</p><ul><li><strong>Active</strong> — the normal operating state.</li><li><strong>Suspended</strong> — paused for non-payment, abuse, or admin action. Users cannot sign in.</li><li><strong>Churned</strong> — the customer is gone. Data is retained per policy but the customer cannot be reactivated automatically.</li></ul><p>See <a href="./statuses">Lifecycle Statuses</a> for transition rules.</p><h2 id="tenant" tabindex="-1">Tenant <a class="header-anchor" href="#tenant" aria-label="Permalink to &quot;Tenant&quot;">​</a></h2><p>A <strong>tenant</strong> is one customer&#39;s environment inside one instance. Tenants are where the customer&#39;s own end-users sign in to do work.</p><p>A tenant has:</p><ul><li>A <strong>name</strong> and a <strong>code</strong> (the immutable identifier the underlying instance uses).</li><li>An <strong>environment tag</strong> — DEV, QA, UAT, STAGING, DEMO, PRE_PROD, or PROD. Environment is used by billing rules and release pipelines.</li><li>An <strong>instance</strong> — the hosted environment where it actually runs. A tenant lives on exactly one instance at a time but can be moved.</li><li>A <strong>licensing profile</strong> — user license count, project license count, license expiration, feature flags (GeoTagging, Angular Dashboard, PowerBI Dashboard), and module list.</li><li><strong>Primary contact</strong> and <strong>address</strong> information for the customer.</li></ul><p>Tenants have a lifecycle:</p><ul><li><strong>Provisioning</strong> — being created on the target instance.</li><li><strong>Active</strong> — operating normally.</li><li><strong>Suspended</strong> — paused; users cannot sign in to the tenant.</li><li><strong>Archived</strong> — retired from active use but data retained. Archive requires a reason.</li></ul><p>Tenants can be <strong>moved</strong> to a different customer (with care; assignments and grants are relinked) and <strong>migrated</strong> to a different instance via the Migrations page.</p><h2 id="instance" tabindex="-1">Instance <a class="header-anchor" href="#instance" aria-label="Permalink to &quot;Instance&quot;">​</a></h2><p>An <strong>instance</strong> is a hosted environment that runs tenants. Think of it as a Kubernetes cluster or a hosted backend.</p><p>An instance has:</p><ul><li>A <strong>name</strong>, <strong>region</strong>, and <strong>environment tag</strong>.</li><li>A <strong>capacity</strong> — the maximum number of tenants it can host.</li><li>A set of <strong>services</strong> — the deployed pods that make up the application. Each service has an image, a version, replicas, and reports its own health.</li><li>A set of <strong>environment variables</strong> — global values plus per-instance overrides. Variables can be plain values, references to Kubernetes secrets, or references to ConfigMaps.</li></ul><p>Instances have a lifecycle:</p><ul><li><strong>Provisioning</strong> — being prepared. After the Console creates an instance, the operator deploys the Console agent into the cluster using the issued bootstrap credentials. Once the agent reports in, the instance becomes active.</li><li><strong>Active</strong> — operating normally. Health is reported via the agent&#39;s heartbeat.</li><li><strong>Inactive</strong> — heartbeat missing for long enough that the Console no longer trusts the state.</li><li><strong>Decommissioned</strong> — retired permanently.</li></ul><h2 id="how-they-fit-together" tabindex="-1">How they fit together <a class="header-anchor" href="#how-they-fit-together" aria-label="Permalink to &quot;How they fit together&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A customer &quot;Acme Corp&quot; buys the &quot;Professional&quot; plan.</span></span>
<span class="line"><span>  └─ Tenant &quot;acme-prod&quot;   (env: PROD)    runs on instance &quot;prod-east-1&quot;</span></span>
<span class="line"><span>  └─ Tenant &quot;acme-uat&quot;    (env: UAT)     runs on instance &quot;stg-east-1&quot;</span></span>
<span class="line"><span>  └─ Tenant &quot;acme-dev&quot;    (env: DEV)     runs on instance &quot;stg-east-1&quot;</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Diagram</p><p><em>Replace the ASCII block with a real diagram:</em> customer node connected to its tenants, each tenant connected to its hosting instance. Colour each tenant by environment.</p></div><p>When a release ships, the Console looks at the pipeline configuration, finds which instances are in each stage, and deploys to those instances. Tenants on those instances pick up the change automatically — there is no per-tenant deployment.</p><p>When a tenant is <strong>moved</strong> between customers, its environment, licensing, and instance stay the same; only ownership and billing change. When a tenant is <strong>migrated</strong>, the Console packages its data, ships it to a different instance, and updates routing. See <a href="./../admin/migrations">Migrations</a>.</p>`,27)])])}const d=t(o,[["render",i]]);export{p as __pageData,d as default};
